"use client";

import { useEffect, useMemo, useRef, useState } from "react";

/* =======================
   TYPE & STORAGE
======================= */

type Usulan = {
  id: string;
  esl: string;
  jabatan: string;
  nama: string;
  pktGol: string;
  nrpNip: string;
  createdAt: string;
  updatedAt?: string;
};

type Row = {
  no: number;
  usulanId?: string;

  esl: string;
  jabatan: string;
  namaPktGolNrpNip: string;

  kondisi: string;
  calonPengisiJabatan: string;
  catatan: string;
  ket: string;
};

const DEFAULT_ROWS = 2;
const STORAGE_KEY_USULAN = "bnn_usulan_v1";

/* =======================
   HELPERS
======================= */

function loadUsulan(): Usulan[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = localStorage.getItem(STORAGE_KEY_USULAN);
    return raw ? (JSON.parse(raw) as Usulan[]) : [];
  } catch {
    return [];
  }
}

function displayUsulan(u: Usulan) {
  const nama = String(u.nama ?? "").trim() || "-";
  const pkt = String(u.pktGol ?? "").trim();
  const nip = String(u.nrpNip ?? "").trim();

  const mid = pkt ? `(PKT/GOL: ${pkt})` : "";
  const right = nip ? `— NRP/NIP: ${nip}` : "";

  return [nama, mid].filter(Boolean).join(" ") + (right ? ` ${right}` : "");
}

function normalize(s: unknown) {
  return String(s ?? "").toLowerCase().trim();
}

/* =======================
   PAGE
======================= */

export default function BuatBahanRapatPage() {
  const [tanggal, setTanggal] = useState("");
  const [materiRapat, setMateriRapat] = useState("");

  const [usulanList, setUsulanList] = useState<Usulan[]>([]);
  const usulanOptions = useMemo(
    () => usulanList.map((u) => displayUsulan(u)),
    [usulanList]
  );

  const [rows, setRows] = useState<Row[]>(
    Array.from({ length: DEFAULT_ROWS }, (_, i) => ({
      no: i + 1,
      usulanId: "",
      esl: "",
      jabatan: "",
      namaPktGolNrpNip: "",
      kondisi: "",
      calonPengisiJabatan: "",
      catatan: "",
      ket: "",
    }))
  );

  useEffect(() => {
    setUsulanList(loadUsulan());
  }, []);

  const canSave = useMemo(() => Boolean(tanggal.trim()), [tanggal]);

  function updateRow(idx: number, patch: Partial<Row>) {
    setRows((prev) => prev.map((r, i) => (i === idx ? { ...r, ...patch } : r)));
  }

  function applyFromUsulan(idx: number, picked: Usulan) {
    updateRow(idx, {
      usulanId: picked.id,
      esl: picked.esl ?? "",
      jabatan: picked.jabatan ?? "",
      namaPktGolNrpNip: displayUsulan(picked),
    });
  }

  function onPickNama(idx: number, pickedLabel: string) {
    const match = usulanList.find((u) => displayUsulan(u) === pickedLabel);
    if (match) {
      applyFromUsulan(idx, match);
      return;
    }
    // kalau tidak match -> tetap isi text biasa (manual)
    updateRow(idx, { usulanId: "", namaPktGolNrpNip: pickedLabel });
  }

  function addRow() {
    setRows((prev) => [
      ...prev,
      {
        no: prev.length + 1,
        usulanId: "",
        esl: "",
        jabatan: "",
        namaPktGolNrpNip: "",
        kondisi: "",
        calonPengisiJabatan: "",
        catatan: "",
        ket: "",
      },
    ]);
  }

  function removeLastRow() {
    setRows((prev) => {
      if (prev.length <= 1) return prev;
      return prev.slice(0, -1).map((r, i) => ({ ...r, no: i + 1 }));
    });
  }

  function onSave() {
    const payload = { tanggal, materiRapat, rows };
    console.log("SAVE bahan rapat:", payload);
    alert("Tersimpan (dummy). Silakan sambungkan ke penyimpanan kamu ya.");
  }

  return (
    <div className="px-2 py-2">
      <div className="mx-auto w-full max-w-[1100px] rounded-md bg-white shadow-[0_14px_40px_rgba(0,0,0,0.18)] ring-1 ring-black/5">
        <div className="p-10">
          {/* Header */}
          <div className="flex items-start justify-between gap-6">
            <div className="text-[11px] font-semibold text-zinc-900">
              <div>BADAN NARKOTIKA NASIONAL</div>
              <div>REPUBLIK INDONESIA</div>
              <div className="mt-2 h-[2px] w-[190px] bg-zinc-700/70" />
            </div>

            <div className="flex-1 pt-1 text-center">
              <div className="text-sm font-bold tracking-wide text-zinc-900">
                MATERI RAPAT
              </div>

              {/* Materi rapat: auto height */}
              <div className="mx-auto mt-3 w-full max-w-[420px]">
                <AutoTextarea
                  value={materiRapat}
                  onChange={setMateriRapat}
                  minRows={2}
                  placeholder="Tulis materi rapat di sini..."
                  className="border-zinc-300 text-sm"
                />
              </div>

              {/* Tanggal */}
              <div className="mt-4 flex items-center justify-center gap-3">
                <div className="text-sm font-semibold text-zinc-900">
                  Tanggal
                </div>
                <input
                  type="date"
                  value={tanggal}
                  onChange={(e) => setTanggal(e.target.value)}
                  className="h-9 w-[170px] rounded-md border border-zinc-300 bg-white px-2 text-xs text-zinc-900 outline-none focus:border-[#123473] focus:ring-2 focus:ring-[#123473]/20"
                />
              </div>
            </div>

            <div className="w-[190px]" />
          </div>

          {/* Table */}
          <div className="mt-8 overflow-x-auto">
            <table className="w-full border border-zinc-700 text-[12px] text-zinc-900">
              <thead>
                <tr className="bg-zinc-200/80">
                  <Th className="w-[60px] text-center">NO</Th>
                  <Th className="w-[90px] text-center">ESL</Th>
                  <Th className="w-[220px] text-center">JABATAN</Th>
                  <Th className="w-[360px] text-center">
                    NAMA / PKT-GOL / NRP-NIP
                    <div className="mt-1 text-[10px] font-normal text-zinc-600">
                      ketik untuk cari dari Daftar Usulan
                    </div>
                  </Th>
                  <Th className="w-[160px] text-center">KONDISI</Th>
                  <Th className="w-[220px] text-center">
                    CALON PENGISI <br /> JABATAN
                  </Th>
                  <Th className="w-[200px] text-center">CATATAN</Th>
                  <Th className="w-[120px] text-center">KET</Th>
                </tr>
              </thead>

              <tbody>
                {rows.map((r, idx) => (
                  <tr key={r.no} className="border-t border-zinc-700">
                    <Td className="text-center">{r.no}.</Td>

                    <Td>
                      <CellInput
                        value={r.esl}
                        onChange={(v) => updateRow(idx, { esl: v })}
                      />
                    </Td>

                    <Td>
                      <CellTextarea
                        value={r.jabatan}
                        onChange={(v) => updateRow(idx, { jabatan: v })}
                        minRows={1}
                      />
                    </Td>

                    {/* ✅ AUTOCOMPLETE (dropdown scroll sendiri, tabel tidak ikut) */}
                    <Td>
                      <div className="space-y-1">
                        <AutocompleteInput
                          value={r.namaPktGolNrpNip}
                          onChange={(v) =>
                            updateRow(idx, { namaPktGolNrpNip: v, usulanId: "" })
                          }
                          onPick={(picked) => onPickNama(idx, picked)}
                          options={usulanOptions}
                          placeholder="Cari nama pegawai..."
                        />
                        {r.usulanId ? (
                          <div className="text-[10px] text-emerald-700">
                            Terhubung dengan Daftar Usulan ✅
                          </div>
                        ) : r.namaPktGolNrpNip.trim() ? (
                          <div className="text-[10px] text-zinc-500">
                            Kamu bisa pilih dari list, atau isi manual.
                          </div>
                        ) : null}
                      </div>
                    </Td>

                    {/* Kondisi: multiline */}
                    <Td>
                      <CellTextarea
                        value={r.kondisi}
                        onChange={(v) => updateRow(idx, { kondisi: v })}
                        minRows={2}
                      />
                    </Td>

                    <Td>
                      <CellTextarea
                        value={r.calonPengisiJabatan}
                        onChange={(v) =>
                          updateRow(idx, { calonPengisiJabatan: v })
                        }
                        minRows={1}
                      />
                    </Td>

                    <Td>
                      <CellTextarea
                        value={r.catatan}
                        onChange={(v) => updateRow(idx, { catatan: v })}
                        minRows={2}
                      />
                    </Td>

                    <Td>
                      <CellTextarea
                        value={r.ket}
                        onChange={(v) => updateRow(idx, { ket: v })}
                        minRows={1}
                      />
                    </Td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Controls */}
          <div className="mt-6 flex items-center justify-between gap-4">
            <div className="flex items-center gap-2">
              <button type="button" onClick={addRow} className="btn">
                + Baris
              </button>
              <button type="button" onClick={removeLastRow} className="btn">
                - Baris
              </button>
            </div>

            <button
              type="button"
              onClick={onSave}
              disabled={!canSave}
              className="btn-primary"
            >
              Simpan
            </button>
          </div>

          <div className="mt-10 text-[10px] text-zinc-700">
            <div>Biro SDM Aparatur dan Organisasi</div>
            <div>Sekretariat Utama BNN 2026</div>
          </div>
        </div>
      </div>
    </div>
  );
}

/* =======================
   UI HELPERS
======================= */

function Th({
  children,
  className = "",
}: {
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <th
      className={["border border-zinc-700 px-3 py-2 font-bold", className].join(
        " "
      )}
    >
      {children}
    </th>
  );
}

function Td({
  children,
  className = "",
}: {
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <td
      className={[
        "align-top border border-zinc-700 px-2 py-2",
        className,
      ].join(" ")}
    >
      {children}
    </td>
  );
}

function CellInput({
  value,
  onChange,
}: {
  value: string;
  onChange: (v: string) => void;
}) {
  return (
    <input
      value={value}
      onChange={(e) => onChange(e.target.value)}
      className="h-9 w-full rounded-md border border-zinc-300 bg-white px-2 text-[12px] outline-none focus:border-[#123473] focus:ring-2 focus:ring-[#123473]/20"
    />
  );
}

/** multiline + auto height (tabel cell) */
function CellTextarea({
  value,
  onChange,
  minRows = 1,
}: {
  value: string;
  onChange: (v: string) => void;
  minRows?: number;
}) {
  const ref = useRef<HTMLTextAreaElement | null>(null);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    el.style.height = "auto";
    el.style.height = `${el.scrollHeight}px`;
  }, [value]);

  return (
    <textarea
      ref={ref}
      rows={minRows}
      value={value}
      onChange={(e) => onChange(e.target.value)}
      className={[
        "w-full resize-none overflow-hidden",
        "rounded-md border border-zinc-300 bg-white px-2 py-2 text-[12px] text-zinc-900",
        "leading-5 outline-none",
        "focus:border-[#123473] focus:ring-2 focus:ring-[#123473]/20",
      ].join(" ")}
    />
  );
}

/** multiline + auto height (materi rapat) */
function AutoTextarea({
  value,
  onChange,
  minRows = 2,
  placeholder,
  className = "",
}: {
  value: string;
  onChange: (v: string) => void;
  minRows?: number;
  placeholder?: string;
  className?: string;
}) {
  const ref = useRef<HTMLTextAreaElement | null>(null);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    el.style.height = "auto";
    el.style.height = `${el.scrollHeight}px`;
  }, [value]);

  return (
    <textarea
      ref={ref}
      rows={minRows}
      value={value}
      placeholder={placeholder}
      onChange={(e) => onChange(e.target.value)}
      className={[
        "w-full resize-none overflow-hidden",
        "rounded-md border bg-white px-3 py-2 text-zinc-900 outline-none",
        "focus:border-[#123473] focus:ring-2 focus:ring-[#123473]/20",
        className,
      ].join(" ")}
    />
  );
}

/* =======================
   AUTOCOMPLETE (CUSTOM)
   ✅ dropdown scroll sendiri
   ✅ tidak ikut overflow tabel
   ✅ bisa ganti pilihan berkali-kali
======================= */

function AutocompleteInput({
  value,
  onChange,
  onPick,
  options,
  placeholder,
}: {
  value: string;
  onChange: (v: string) => void;
  onPick: (picked: string) => void;
  options: string[];
  placeholder?: string;
}) {
  const [open, setOpen] = useState(false);
  const [activeIndex, setActiveIndex] = useState(0);

  const filtered = useMemo(() => {
    const q = normalize(value);
    if (!q) return options.slice(0, 30);
    return options
      .filter((x) => normalize(x).includes(q))
      .slice(0, 50);
  }, [value, options]);

  function pick(v: string) {
    onPick(v);
    setOpen(false);
  }

  return (
    <div className="relative">
      <input
        value={value}
        onChange={(e) => {
          onChange(e.target.value);
          setOpen(true);
          setActiveIndex(0);
        }}
        onFocus={() => setOpen(true)}
        onBlur={() => setTimeout(() => setOpen(false), 120)}
        onKeyDown={(e) => {
          if (!open) return;

          if (e.key === "ArrowDown") {
            e.preventDefault();
            setActiveIndex((i) => Math.min(i + 1, filtered.length - 1));
          } else if (e.key === "ArrowUp") {
            e.preventDefault();
            setActiveIndex((i) => Math.max(i - 1, 0));
          } else if (e.key === "Enter") {
            e.preventDefault();
            const v = filtered[activeIndex];
            if (v) pick(v);
          } else if (e.key === "Escape") {
            setOpen(false);
          }
        }}
        placeholder={placeholder}
        className="h-10 w-full rounded-md border border-zinc-300 bg-white px-2 text-[12px] outline-none focus:border-[#123473] focus:ring-2 focus:ring-[#123473]/20"
      />

      {open && filtered.length > 0 && (
        <div className="absolute left-0 right-0 top-[calc(100%+6px)] z-50 rounded-md border border-zinc-200 bg-white shadow-lg">
          {/* ✅ yang scroll cuma list dropdown */}
          <div className="max-h-56 overflow-y-auto py-1">
            {filtered.map((opt, idx) => (
              <button
                key={`${opt}-${idx}`}
                type="button"
                onMouseDown={(e) => e.preventDefault()} // biar ga keburu blur
                onClick={() => pick(opt)}
                className={[
                  "block w-full px-3 py-2 text-left text-[12px]",
                  "hover:bg-zinc-50",
                  idx === activeIndex ? "bg-[#123473]/5" : "",
                ].join(" ")}
                title={opt}
              >
                {opt}
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
